body.script:
  const urls = [
    { url: "https://brightlane.github.io/aliexpress.com/", priority: 1.0 },
    { url: "https://brightlane.github.io/aliexpress.com/1000lumen-led-lantern.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/100w.-solar-panel-.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/120db-survival-whistle.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/201-water-bladder.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/5501-paranoid-bracelet.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/Emergency-Mylar-Survival-Blanket.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/LifeStream-Portable-Water-Filter.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/MagSafeHub.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/Portable-Power-Banks.html", priority: 0.9 },
    { url: "https://brightlane.github.io/aliexpress.com/StormReadyHub.html", priority: 0.9 }
    // Add the rest of your URLs here
  ];

  const container = document.querySelector(".url-list");
  const searchInput = document.getElementById("search");

  function renderList(filter = "") {
    container.innerHTML = "";
    const filtered = urls.filter(item => item.url.toLowerCase().includes(filter.toLowerCase()));
    filtered.forEach(item => {
      const div = document.createElement("div");
      div.className = "url-item";
      div.innerHTML = `${item.url}

Priority: ${item.priority}`;
      container.appendChild(div);
    });
  }

  searchInput.addEventListener("input", () => renderList(searchInput.value));

  // Initial render
  renderList();
